-- REVIEW:   -- ── CONVERSATION_PARTICIPANTS ─────────────────────────────────────
-- REVIEW:   -- conversation_participants → unified_conversations (conversation_id)
-- REVIEW:   RETURN QUERY
-- REVIEW:   SELECT 'conversation_participants'::TEXT, 'conversation_id'::TEXT, 'unified_conversations'::TEXT,
